import{_ as e,o as l,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse(`{"title":"Functies | Dotfiles (NL)","titleTemplate":":title","description":"Shell-functies die je terminal-ervaring verbeteren. Hulpprogramma's voor API-testen, bestandsbeheer, systeemoperaties en meer.","frontmatter":{"title":"Functies | Dotfiles","description":"Shell-functies die je terminal-ervaring verbeteren. Hulpprogramma's voor API-testen, bestandsbeheer, systeemoperaties en meer.","lang":"nl-NL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Functies preview","canonical":"/nl/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Functies","pageType":"docs","schemaType":"WebPage","metaTitle":"Functies - Dotfiles (NL)","permalink":"/nl/functions/","meta":[{"name":"keywords","content":"functies, shell, bash, zsh, dotfiles, productiviteit, hulpprogramma's, api, bestand, systeem"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Shell-functies die je terminal-ervaring verbeteren. Hulpprogramma's voor API-testen, bestandsbeheer, systeemoperaties en meer."},{"name":"twitter:title","content":"Functies - Dotfiles"},{"name":"og:title","content":"Functies - Dotfiles"},{"name":"og:description","content":"Shell-functies die je terminal-ervaring verbeteren. Hulpprogramma's voor API-testen, bestandsbeheer, systeemoperaties en meer."},{"name":"og:image:alt","content":"Dotfiles - Eenvoudig ontworpen om bij je shell-leven te passen"},{"name":"og:locale","content":"nl_NL"}]},"headers":[],"relativePath":"nl/functions/index.md","filePath":"nl/functions/index.md","lastUpdated":1773010926000}`),i={name:"nl/functions/index.md"};function n(o,t,s,r,c,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="functies" tabindex="-1">Functies <a class="header-anchor" href="#functies" aria-label="Permalink to &quot;Functies&quot;">​</a></h1><p>Shell-hulpprogramma&#39;s om je productiviteit te verhogen op macOS, Linux en Windows.</p><h2 id="ontdek" tabindex="-1">Ontdek <a class="header-anchor" href="#ontdek" aria-label="Permalink to &quot;Ontdek&quot;">​</a></h2><p>Functies worden gedefinieerd als individuele <code>.sh</code>-bestanden. Tijdens <code>chezmoi apply</code> worden ze samengevoegd in <code>~/.config/shell/functions.sh</code> en door je shell geladen.</p><h2 id="aan-de-slag" tabindex="-1">Aan de slag <a class="header-anchor" href="#aan-de-slag" aria-label="Permalink to &quot;Aan de slag&quot;">​</a></h2><h3 id="een-functie-toevoegen" tabindex="-1">Een functie toevoegen <a class="header-anchor" href="#een-functie-toevoegen" aria-label="Permalink to &quot;Een functie toevoegen&quot;">​</a></h3><ol><li>Maak een nieuw <code>.sh</code>-bestand aan (bijv. <code>myfunc.sh</code>)</li><li>Voeg je functiedefinitie toe</li><li>Pas wijzigingen toe:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="referentie" tabindex="-1">Referentie <a class="header-anchor" href="#referentie" aria-label="Permalink to &quot;Referentie&quot;">​</a></h2><h3 id="api-testen" tabindex="-1">API-testen <a class="header-anchor" href="#api-testen" aria-label="Permalink to &quot;API-testen&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">Controleer gezondheid van een of meerdere API&#39;s</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">Monitor API-responstijd</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">Voer eenvoudige load-testen uit</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">Debug HTTP-verzoeken met timing</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="http-hulpprogramma-s" tabindex="-1">HTTP-hulpprogramma&#39;s <a class="header-anchor" href="#http-hulpprogramma-s" aria-label="Permalink to &quot;HTTP-hulpprogramma&#39;s&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">Bekijk HTTP-headers</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">Controleer HTTP-statuscode</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">Meet HTTP-timing-metrieken</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">Bekijk broncode van website</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">Vind proces dat een poort gebruikt</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="bestandsbeheer" tabindex="-1">Bestandsbeheer <a class="header-anchor" href="#bestandsbeheer" aria-label="Permalink to &quot;Bestandsbeheer&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">Maak back-ups met tijdstempel</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Base64-codering en -decodering</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">Pak archiefformaten uit</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">Toon bestand in hex-formaat</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">Batch hernoem extensies</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">Controleer bestand- of mapgrootte</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">Maak ZIP-archieven</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="bestandsnaamgeving" tabindex="-1">Bestandsnaamgeving <a class="header-anchor" href="#bestandsnaamgeving" aria-label="Permalink to &quot;Bestandsnaamgeving&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">Converteer naar kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">Converteer naar kleine letters</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">Converteer naar zinsopmaak</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">Converteer naar snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Converteer naar Titelopmaak</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">Converteer naar HOOFDLETTERS</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="systeemhulpprogramma-s" tabindex="-1">Systeemhulpprogramma&#39;s <a class="header-anchor" href="#systeemhulpprogramma-s" aria-label="Permalink to &quot;Systeemhulpprogramma&#39;s&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">Voorkom dat systeem in slaapstand gaat</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">Detecteer OS-omgeving</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">Schoon purgeerbare schijfruimte op</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Schakel verborgen bestanden in Finder</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">Toon hostinformatie</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">Bekijk commando-gebruiksstatistieken</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">Lijst recent gewijzigde bestanden</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">Cross-platform uitloggen</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">Lijst gebruikersprocessen</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">Terminal-stopwatch</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">Toon systeeminformatie</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="caffeine-commando-s" tabindex="-1">Caffeine-commando&#39;s <a class="header-anchor" href="#caffeine-commando-s" aria-label="Permalink to &quot;Caffeine-commando&#39;s&quot;">​</a></h3><p>Voorkom dat je systeem in slaapstand gaat of de screensaver activeert.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Commando</th><th style="text-align:left;">Beschrijving</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">Start de caffeine-daemon</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">Controleer of daemon draait</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">Houd het scherm wakker</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">Sta toe dat scherm slaapt</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">Schakel scherm wakker</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">Sluit de daemon af</td></tr></tbody></table><p>Werkt op macOS (native <code>caffeinate</code>), Linux (<code>xdg-screensaver</code>) en Windows (PowerShell).</p><h3 id="beveiliging" tabindex="-1">Beveiliging <a class="header-anchor" href="#beveiliging" aria-label="Permalink to &quot;Beveiliging&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">Genereer sterke wachtwoorden</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">Genereer SSH-sleutelparen</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="navigatie" tabindex="-1">Navigatie <a class="header-anchor" href="#navigatie" aria-label="Permalink to &quot;Navigatie&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">Wijzig map en toon lijst</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">Snelle mapnavigatie</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">Koppel alleen-lezen als lezen-schrijven</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">Verwijder map</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">Verwijder schijf veilig</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="diversen" tabindex="-1">Diversen <a class="header-anchor" href="#diversen" aria-label="Permalink to &quot;Diversen&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Functie</th><th style="text-align:left;">Beschrijving</th><th style="text-align:left;">Gebruik</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">Terminal Matrix-effecten</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">Voeg map toe aan PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">Open in macOS Quick Look</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">Open in VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="compatibiliteit" tabindex="-1">Compatibiliteit <a class="header-anchor" href="#compatibiliteit" aria-label="Permalink to &quot;Compatibiliteit&quot;">​</a></h2><ul><li><strong>macOS</strong> — Volledige ondersteuning met macOS-specifieke hulpprogramma&#39;s</li><li><strong>Linux</strong> — Compatibel met gangbare distributies</li><li><strong>Windows</strong> — Ondersteuning via WSL, Cygwin of Git Bash</li></ul><h2 id="help" tabindex="-1">Help <a class="header-anchor" href="#help" aria-label="Permalink to &quot;Help&quot;">​</a></h2><p>Elke functie bevat documentatie via <code>--help</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(i,[["render",n]]);export{h as __pageData,y as default};
